/**
 * SymbolSearch — Fast autocomplete search for symbols.
 * Shows company name, sector, market cap alongside ticker.
 * Stores recent searches in localStorage.
 */
import { useState, useEffect, useRef, useCallback } from 'react';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';

const C = {
  bg: tokens.color.bg,
  surface: tokens.color.surface,
  surface2: tokens.color.surfaceHover,
  border: tokens.color.border,
  text: tokens.color.text,
  textSec: tokens.color.textSecondary,
  blue: tokens.color.blue,
  green: tokens.color.green,
  purple: tokens.color.purple,
  amber: tokens.color.amber,
};

const RECENT_KEY = 'aura_recent_symbol_searches';
const MAX_RECENT = 8;

function getRecent() {
  try {
    return JSON.parse(localStorage.getItem(RECENT_KEY) || '[]').slice(0, MAX_RECENT);
  } catch {
    return [];
  }
}

function saveRecent(symbol) {
  const recent = getRecent().filter((s) => s !== symbol);
  recent.unshift(symbol);
  localStorage.setItem(RECENT_KEY, JSON.stringify(recent.slice(0, MAX_RECENT)));
}

function capBadge(cap) {
  if (!cap) return null;
  const colors = {
    Mega: C.green,
    Large: C.blue,
    Mid: C.amber,
    ETF: C.purple,
    Crypto: '#F97316',
  };
  return (
    <span
      style={{
        fontSize: 9,
        fontWeight: 700,
        padding: '1px 5px',
        borderRadius: 3,
        background: (colors[cap] || C.textSec) + '22',
        color: colors[cap] || C.textSec,
        textTransform: 'uppercase',
        letterSpacing: 0.5,
        whiteSpace: 'nowrap',
      }}
    >
      {cap}
    </span>
  );
}

export default function SymbolSearch({
  onSelect,
  placeholder = 'Search symbols...',
  autoFocus = false,
  compact = false,
  showRecent = true,
}) {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);
  const [recent, setRecent] = useState([]);
  const [highlightIdx, setHighlightIdx] = useState(-1);
  const inputRef = useRef(null);
  const dropdownRef = useRef(null);
  const debounceRef = useRef(null);

  useEffect(() => {
    if (showRecent) setRecent(getRecent());
  }, [showRecent]);

  // Close dropdown on outside click
  useEffect(() => {
    function handleClick(e) {
      if (
        dropdownRef.current &&
        !dropdownRef.current.contains(e.target) &&
        inputRef.current &&
        !inputRef.current.contains(e.target)
      ) {
        setOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  const search = useCallback(async (q) => {
    if (!q.trim()) {
      setResults([]);
      return;
    }
    setLoading(true);
    try {
      const data = await api(`/data/symbols/search?q=${encodeURIComponent(q)}&limit=15`);
      if (data?.results && data.results.length > 0) {
        setResults(data.results);
      } else {
        // Fallback: fetch full symbol cache and filter client-side
        const cacheData = await api('/data/cache/symbols');
        const allSymbols = cacheData?.symbols || cacheData?.results || (Array.isArray(cacheData) ? cacheData : []);
        const qUp = q.trim().toUpperCase();
        const filtered = allSymbols
          .filter((s) => {
            const sym = typeof s === 'string' ? s : s?.symbol || s?.ticker || '';
            const name = typeof s === 'object' ? (s?.name || '') : '';
            return sym.toUpperCase().startsWith(qUp) || sym.toUpperCase().includes(qUp) ||
                   name.toUpperCase().includes(qUp);
          })
          .slice(0, 15)
          .map((s) => typeof s === 'string' ? { symbol: s } : { symbol: s.symbol || s.ticker, name: s.name, sector: s.sector, cap: s.cap });
        setResults(filtered);
      }
    } catch {
      // Last-resort: try client-side cache directly
      try {
        const cacheData = await api('/data/cache/symbols');
        const allSymbols = cacheData?.symbols || cacheData?.results || (Array.isArray(cacheData) ? cacheData : []);
        const qUp = q.trim().toUpperCase();
        const filtered = allSymbols
          .filter((s) => {
            const sym = typeof s === 'string' ? s : s?.symbol || s?.ticker || '';
            return sym.toUpperCase().startsWith(qUp) || sym.toUpperCase().includes(qUp);
          })
          .slice(0, 15)
          .map((s) => typeof s === 'string' ? { symbol: s } : { symbol: s.symbol || s.ticker, name: s.name });
        setResults(filtered);
      } catch {
        setResults([]);
      }
    }
    setLoading(false);
  }, []);

  const handleChange = (e) => {
    const val = e.target.value;
    setQuery(val);
    setOpen(true);
    setHighlightIdx(-1);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => search(val), 150);
  };

  const handleSelect = (symbol) => {
    setQuery('');
    setResults([]);
    setOpen(false);
    saveRecent(symbol);
    setRecent(getRecent());
    if (onSelect) onSelect(symbol);
  };

  const handleKeyDown = (e) => {
    const items = query.trim() ? results : (showRecent ? recent.map((s) => ({ symbol: s })) : []);
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setHighlightIdx((prev) => Math.min(prev + 1, items.length - 1));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setHighlightIdx((prev) => Math.max(prev - 1, -1));
    } else if (e.key === 'Enter') {
      e.preventDefault();
      if (highlightIdx >= 0 && highlightIdx < items.length) {
        handleSelect(items[highlightIdx].symbol || items[highlightIdx]);
      } else if (query.trim()) {
        handleSelect(query.trim().toUpperCase());
      }
    } else if (e.key === 'Escape') {
      setOpen(false);
    }
  };

  const showDropdown = open && (query.trim() ? results.length > 0 || loading : showRecent && recent.length > 0);

  return (
    <div style={{ position: 'relative', width: compact ? 220 : '100%' }}>
      <div style={{ position: 'relative' }}>
        {/* Search icon */}
        <svg
          width="14"
          height="14"
          viewBox="0 0 24 24"
          fill="none"
          stroke={C.textSec}
          strokeWidth="2"
          style={{ position: 'absolute', left: 10, top: '50%', transform: 'translateY(-50%)', pointerEvents: 'none' }}
        >
          <circle cx="11" cy="11" r="8" />
          <line x1="21" y1="21" x2="16.65" y2="16.65" />
        </svg>
        <input
          ref={inputRef}
          type="text"
          value={query}
          onChange={handleChange}
          onFocus={() => setOpen(true)}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          autoFocus={autoFocus}
          style={{
            width: '100%',
            boxSizing: 'border-box',
            padding: compact ? '6px 10px 6px 30px' : '8px 12px 8px 32px',
            fontSize: 13,
            fontFamily: tokens.font.mono,
            background: C.surface2,
            border: `1px solid ${C.border}`,
            borderRadius: 6,
            color: C.text,
            outline: 'none',
          }}
        />
        {loading && (
          <div
            style={{
              position: 'absolute',
              right: 10,
              top: '50%',
              transform: 'translateY(-50%)',
              width: 14,
              height: 14,
              border: `2px solid ${C.border}`,
              borderTop: `2px solid ${C.blue}`,
              borderRadius: '50%',
              animation: 'symbolSearchSpin 0.6s linear infinite',
            }}
          />
        )}
      </div>

      {showDropdown && (
        <div
          ref={dropdownRef}
          style={{
            position: 'absolute',
            top: '100%',
            left: 0,
            right: 0,
            marginTop: 4,
            background: C.surface,
            border: `1px solid ${C.border}`,
            borderRadius: 8,
            boxShadow: '0 8px 24px rgba(0,0,0,0.4)',
            zIndex: 100,
            maxHeight: 320,
            overflowY: 'auto',
          }}
        >
          {/* Recent searches */}
          {!query.trim() && showRecent && recent.length > 0 && (
            <>
              <div
                style={{
                  padding: '8px 12px 4px',
                  fontSize: 10,
                  fontWeight: 600,
                  color: C.textSec,
                  textTransform: 'uppercase',
                  letterSpacing: 1,
                }}
              >
                Recent Searches
              </div>
              {recent.map((sym, i) => (
                <div
                  key={sym}
                  onClick={() => handleSelect(sym)}
                  style={{
                    padding: '8px 12px',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    gap: 8,
                    background: highlightIdx === i ? C.surface2 : 'transparent',
                    transition: 'background 0.1s',
                  }}
                  onMouseEnter={() => setHighlightIdx(i)}
                >
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={C.textSec} strokeWidth="2">
                    <circle cx="12" cy="12" r="10" />
                    <polyline points="12 6 12 12 16 14" />
                  </svg>
                  <span style={{ fontFamily: tokens.font.mono, fontSize: 13, fontWeight: 600, color: C.text }}>
                    {sym}
                  </span>
                </div>
              ))}
            </>
          )}

          {/* Search results */}
          {query.trim() &&
            results.map((r, i) => (
              <div
                key={r.symbol}
                onClick={() => handleSelect(r.symbol)}
                style={{
                  padding: '8px 12px',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 10,
                  background: highlightIdx === i ? C.surface2 : 'transparent',
                  transition: 'background 0.1s',
                  borderBottom: i < results.length - 1 ? `1px solid ${C.border}22` : 'none',
                }}
                onMouseEnter={() => setHighlightIdx(i)}
              >
                <div style={{ flex: '0 0 auto' }}>
                  <div style={{ fontFamily: tokens.font.mono, fontSize: 13, fontWeight: 700, color: C.blue }}>
                    {r.symbol}
                  </div>
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div
                    style={{
                      fontSize: 12,
                      color: C.text,
                      whiteSpace: 'nowrap',
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                    }}
                  >
                    {r.name || r.symbol}
                  </div>
                  {r.sector && (
                    <div style={{ fontSize: 10, color: C.textSec, marginTop: 1 }}>{r.sector}</div>
                  )}
                </div>
                {capBadge(r.cap)}
              </div>
            ))}

          {query.trim() && results.length === 0 && !loading && (
            <div style={{ padding: '16px 12px', textAlign: 'center', fontSize: 12, color: C.textSec }}>
              No symbols found for "{query}"
            </div>
          )}
        </div>
      )}

      <style>{`@keyframes symbolSearchSpin { to { transform: translateY(-50%) rotate(360deg); } }`}</style>
    </div>
  );
}
